import React, { useState } from 'react';
import { LayoutVisualData } from '../types';

type LayoutType = 'staggered';

interface KeyboardVisualizationProps {
  layoutData: LayoutVisualData;
  highlightedKeys?: string[];
  className?: string;
  onKeyHover?: (key: string) => void;
  showFingerColors?: boolean;
}

interface KeyProps {
  char: string;
  position: string;
  finger?: number;
  isHighlighted?: boolean;
  className?: string;
  onHover?: (key: string) => void;
  showFingerColors?: boolean;
}

const Key: React.FC<KeyProps> = ({ 
  char, 
  position, 
  finger = 0,
  isHighlighted = false, 
  className = "",
  onHover,
  showFingerColors = true
}) => {
  const getFingerColor = (finger: number) => {
    const colors = [
      'bg-red-200 dark:bg-red-800 hover:bg-red-300 dark:hover:bg-red-700', // LP (0)
      'bg-orange-200 dark:bg-orange-800 hover:bg-orange-300 dark:hover:bg-orange-700', // LR (1)
      'bg-yellow-200 dark:bg-yellow-800 hover:bg-yellow-300 dark:hover:bg-yellow-700', // LM (2)
      'bg-green-200 dark:bg-green-800 hover:bg-green-300 dark:hover:bg-green-700', // LI (3)
      'bg-blue-200 dark:bg-blue-800 hover:bg-blue-300 dark:hover:bg-blue-700', // LT (4)
      'bg-blue-300 dark:bg-blue-700 hover:bg-blue-400 dark:hover:bg-blue-600', // RT (5)
      'bg-green-300 dark:bg-green-700 hover:bg-green-400 dark:hover:bg-green-600', // RI (6)
      'bg-yellow-300 dark:bg-yellow-700 hover:bg-yellow-400 dark:hover:bg-yellow-600', // RM (7)
      'bg-orange-300 dark:bg-orange-700 hover:bg-orange-400 dark:hover:bg-orange-600', // RR (8)
      'bg-red-300 dark:bg-red-700 hover:bg-red-400 dark:hover:bg-red-600', // RP (9)
    ];
    return colors[finger] || 'bg-gray-300 dark:bg-gray-700 hover:bg-gray-400 dark:hover:bg-gray-600';
  };

  const getKeySize = (pos: string) => {
    // HHKB-specific key sizes
    if (pos === 'tab') return 'w-16';
    if (pos === 'ctrl') return 'w-18';
    if (pos === 'shift') return 'w-24';
    if (pos === 'shift-r') return 'w-20';
    if (pos === 'enter') return 'w-18';
    if (pos === 'space') return 'w-32';
    if (pos === 'backspace') return 'w-16';
    if (pos === 'meta-l' || pos === 'meta-r' || pos === 'alt-l' || pos === 'alt-r' || pos === 'fn') return 'w-12';
    return 'w-12';
  };

  return (
    <div
      className={`
        flex 
        items-center 
        justify-center 
        font-mono 
        text-sm 
        font-semibold
        text-gray-800 
        dark:text-gray-200
        cursor-pointer
        transition-all
        duration-150
        rounded-lg 
        border-2 
        border-gray-300
        dark:border-gray-600
        ${showFingerColors ? getFingerColor(finger) : 'bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600'}
        ${isHighlighted ? 'ring-4 ring-purple-500 ring-opacity-50 scale-105' : ''}
        ${className}
      `}
      onMouseEnter={() => onHover?.(char)}
      title={`${char.toUpperCase()} - Finger ${finger + 1}`}
    >
      {char}
    </div>
  );
};

// Define finger assignments for keys (0-9 mapping to LP, LR, LM, LI, LT, RT, RI, RM, RR, RP)
const getFingerForKey = (key: string): number => {
  const fingerMap: { [key: string]: number } = {
    // Number row
    '`': 0, '1': 0, '2': 1, '3': 2, '4': 3, '5': 3, '6': 6, '7': 6, '8': 7, '9': 8, '0': 9, '-': 9, '=': 9,
    // Top row  
    'q': 0, 'w': 1, 'e': 2, 'r': 3, 't': 3, 'y': 6, 'u': 6, 'i': 7, 'o': 8, 'p': 9, '[': 9, ']': 9,
    // Home row
    'a': 0, 's': 1, 'd': 2, 'f': 3, 'g': 3, 'h': 6, 'j': 6, 'k': 7, 'l': 8, ';': 9, "'": 9,
    // Bottom row
    'z': 0, 'x': 1, 'c': 2, 'v': 3, 'b': 3, 'n': 6, 'm': 6, ',': 7, '.': 8, '/': 9
  };
  return fingerMap[key.toLowerCase()] ?? 4;
};

const KeyboardVisualization: React.FC<KeyboardVisualizationProps> = ({
  layoutData,
  highlightedKeys = [],
  className = "",
  onKeyHover,
  showFingerColors = true
}) => {
  const [layoutType, setLayoutType] = useState<LayoutType>('staggered');
  const keys = layoutData.keys || {};

  const generateTextVisual = (layoutKeys: Record<string, string>) => {
    const rows = [
      ['`', '1', '2', '3', '4', '5', '6', '7', '8', '9', '0', '-', '='],
      ['q', 'w', 'e', 'r', 't', 'y', 'u', 'i', 'o', 'p', '[', ']'],
      ['a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';', '\''],
      ['z', 'x', 'c', 'v', 'b', 'n', 'm', ',', '.', '/']
    ];
    
    return rows.map(row => 
      row.map(key => {
        const char = layoutKeys[key] || key;
        const isHighlighted = highlightedKeys.includes(key);
        return isHighlighted ? `[${char}]` : ` ${char} `;
      }).join('')
    ).join('\n');
  };

  const renderStaggeredLayout = () => (
    <div className="bg-gray-100 dark:bg-gray-800 p-6 rounded-xl shadow-lg max-w-4xl mx-auto">
      <div className="bg-white dark:bg-gray-900 p-4 rounded-lg border">
        <pre className="font-mono text-lg leading-relaxed text-center whitespace-pre-wrap">
          {generateTextVisual(keys)}
        </pre>
      </div>
    </div>
  );



  const getCurrentLayout = () => {
    return renderStaggeredLayout();
  };

  return (
    <div className={`bg-white dark:bg-gray-900 rounded-xl p-6 ${className}`}>

      {/* Keyboard Layout */}
      <div className="keyboard-container flex justify-center">
        {getCurrentLayout()}
      </div>
      
      {/* Legend */}
      {showFingerColors && (
        <div className="mt-6 flex flex-wrap gap-2 justify-center text-xs">
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-red-200 dark:bg-red-800 border"></div>
            <span>LP</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-orange-200 dark:bg-orange-800 border"></div>
            <span>LR</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-yellow-200 dark:bg-yellow-800 border"></div>
            <span>LM</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-green-200 dark:bg-green-800 border"></div>
            <span>LI</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-blue-200 dark:bg-blue-800 border"></div>
            <span>Thumb</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-green-300 dark:bg-green-700 border"></div>
            <span>RI</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-yellow-300 dark:bg-yellow-700 border"></div>
            <span>RM</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-orange-300 dark:bg-orange-700 border"></div>
            <span>RR</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-3 h-3 rounded bg-red-300 dark:bg-red-700 border"></div>
            <span>RP</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default KeyboardVisualization;
